mapper.select:
select spi.id as rowId,spi.name as name,csy.name as yearName,spi.sub_no as subNo, huser.name as headName,sdept.name as deptName,spi.sys_no as sysNo, spi.issued_date as issuedDate,spi.end_date as endDate,spi.acceptance_date as acceptanceDate, spi.proj_status as projStatus,spi.special_funds as specialFunds,spi.project_account as projectAccount, spi.enterprise_funds as enterpriseFunds,spi.data_status as dataStatus,spi.sub_date as subDate from srm_projects_info spi left join ct_srm_proj_type cspt on cspt.code=spi.proj_type left join ct_srm_year csy on csy.code=spi.year left join ct_srm_dept sdept on sdept.id=spi.dept_id left join ct_srm_user huser on huser.id=spi.head left join ct_srm_discipline fdiscipline on fdiscipline.code=spi.discipline left join ct_srm_person_type ccspt on ccspt.code=spi.head_type_code left join ct_srm_proj_level cspl on cspl.code=spi.proj_level
where spi.sys_no=#{projectsInfoDto.sysNo}
and (spi.sub_user_id=#{projectsInfoDto.userId} or spi.head=#{projectsInfoDto.userId} or spi.id in (SELECT proj_id FROM srm_projects_info_member WHERE member = #{projectsInfoDto.userId}) )
and spi.name LIKE CONCAT('%', #{projectsInfoDto.name}, '%')
and spi.proj_type = #{projectsInfoDto.projType}
and spi.head = #{projectsInfoDto.head}

select spfc.id as rowId,spi.name as projName,huser.name as subUserName,spfc.sub_date as subDate,
       spfc.proj_id as projRowId,spfc.data_status as dataStatus,spfc.audit_status as auditStatus,
       situation1, situation2, situation3, situation4, situation5, situation6, situation7,
       situation8, situation9, situation10, situation11, situation12,
       situation13, situation14, situation15
from srm_project_finalcheck spfc
         left join srm_projects_info spi on spi.id=spfc.proj_id
         left join ct_srm_user huser on huser.id=spfc.sub_user
where 1=1

    and spfc.sub_user=#{projectFinalcheckDto.userId}


    and spfc.proj_id=#{projectFinalcheckDto.projId}


    and spfc.data_status = #{projectFinalcheckDto.dataStatus}


    and spfc.sys_no = #{projectFinalcheckDto.sysNo}

select spi.id as rowId,spi.name as name,csy.name as yearName,spi.sys_no as sysNo,spi.sub_no as subNo, huser.name as headName,sdept.name as deptName,suser.name as subUserName, spi.issued_date as issuedDate,spi.end_date as endDate,spi.acceptance_date as acceptanceDate, spi.proj_status as projStatus,spi.special_funds as specialFunds,spi.project_account as projectAccount, spi.enterprise_funds as enterpriseFunds,spi.data_status as dataStatus,spi.sub_date as subDate from srm_project_finalcheck spfc left join srm_projects_info spi on spi.id=spfc.proj_id left join ct_srm_proj_type cspt on cspt.code=spi.proj_type left join ct_srm_year csy on csy.code=spi.year left join ct_srm_dept sdept on sdept.id=spi.dept_id left join ct_srm_user huser on huser.id=spi.head left join ct_srm_user suser on suser.id=spi.sub_user_id left join ct_srm_discipline fdiscipline on fdiscipline.code=spi.discipline left join ct_srm_person_type ccspt on ccspt.code=spi.head_type_code left join ct_srm_proj_level cspl on cspl.code=spi.proj_level left join ct_srm_user puser on puser.id=spfc.sub_user left join cf_srm_eaf_rec eafrec on eafrec.sys_no=#{projectFinalcheckDto.sysNo} and eafrec.check_rec_id=spfc.id where spfc.proj_id is not null and eafrec.step_no>1 and spi.sys_no=#{projectFinalcheckDto.prjSysNo}
and ( (spfc.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{projectFinalcheckDto.userId}, '|%')) or (eafrec.step_no = (select max(step_no) from cf_srm_eaf_rec seafrec where seafrec.sys_no=#{projectFinalcheckDto.sysNo} and seafrec.check_rec_id=spfc.id) and eafrec.checker_string LIKE CONCAT('%|', #{projectFinalcheckDto.userId}, '|%') and eafrec.check_datetime is not null) or (spfc.data_status=0 and eafrec.is_current_step=1 and eafrec.check_result=3 and eafrec.checker_string LIKE CONCAT('%|', #{projectFinalcheckDto.userId}, '|%')) )
and spfc.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{projectFinalcheckDto.userId}, '|%')
and spfc.data_status=1 and eafrec.check_result="2" and eafrec.checker_string LIKE CONCAT('%|', #{projectFinalcheckDto.userId}, '|%')
and spfc.data_status=0 and eafrec.check_result="3" and eafrec.checker_string LIKE CONCAT('%|', #{projectFinalcheckDto.userId}, '|%')
and spi.name LIKE CONCAT('%', #{projectFinalcheckDto.projName}, '%')
and spi.proj_type = #{projectFinalcheckDto.projType}
and spi.head = #{projectFinalcheckDto.projHead}
